import { Link } from "react-router-dom";
import { H4 } from "../../../AbstractElements";
import CustomerAction from "../ActionCell/CustomerAction";

export const CustomerArchiveColumns = (authState) => [
    {
        name: <H4>Sl.No</H4>,
        selector: row => row.Si,
        width: '70px'
    },
    {
        name: <H4>Subscriber Id</H4>,
        id: 'subscriber_id',
        selector: row => row.subscriber_id,
        sortable: true,
        wrap: true,
        width: '100px',
        cell: row => (authState.userRole === 1 || authState.permissions.includes('show-customer-profile')) ?
            <Link style={{ textDecoration: 'underline' }} to={`${process.env.PUBLIC_URL}/customers/customer/userProfile?id=${row.id}`}>
                {row.subscriber_id}
            </Link> : row.subscriber_id,
    },
    {
        name: <H4>Name</H4>,
        id: 'name',
        selector: row => row.name,
        sortable: true,
        width: '140px',
        wrap: true
    },
    {
        name: <H4>Status</H4>,
        selector: row => row.Date,
        width: '100px',
        cell: row => (
            <span
                className={`badge badge-${row.Status}`}
            >
                {row.Status}
            </span>
        ),
    },
    {
        name: <H4>Lco no</H4>,
        selector: row => row.Lco,
        id: 'lco_no',
        sortable: true,
        width: '100px',
        wrap: true,
    },
    {
        name: <H4>Mobile No</H4>,
        selector: row => row.Mobile,
        id: 'mobile',
        sortable: true,
        width: '160px',
    },
    {
        name: <H4>Area</H4>,
        selector: row => row.Area,
        id: 'area',
        sortable: true,
    },
    {
        name: <H4>Address</H4>,
        selector: row => row.Address,
        id: 'address',
        sortable: true,
        width: '160px',
        wrap: true,
    },
    {
        name: <H4>Route No</H4>,
        selector: row => row.Route,
        width: '110px',
    },
];

