export const StbColumns = (authState, Action) => [
    {
        name: <H4>Sl.No</H4>,
        selector: row => row.Si,
        width: '70px',
    },
    {
        name: <i className="fa fa-gears" style={{ fontSize: '15px' }}></i>,
        selector: row => row.action,
        cell: row => <Action row={row} />,
        center: true,
        width: '50px',
    },
    {
        name: <H4>Subscriber Id</H4>,
        id: 'subscriber_id',
        selector: row =>
            (authState.userRole === 1 || authState.permissions.includes("show-customer-profile")) ?
                <Link style={{ textDecoration: 'underline' }} to={`${process.env.PUBLIC_URL}/customers/customer/userProfile?id=${row.customer_id}`}>
                    {row.Sub}
                </Link> : row.Sub,
        sortable: true,
        wrap: true,
        width: '130px',
    },
    {
        name: <H4>Name</H4>,
        id: 'customer_name',
        selector: row => row.Name,
        sortable: true,
        wrap: true
    },
    {
        name: <H4>Status</H4>,
        selector: row => row.Status,
        width: '100px',
        cell: row => (
            <div>
                <span
                    className={`badge badge-${row.Status}`}
                >
                    {row.Status}
                </span>
                {row.Status === 'disconnected' && (
                    <span>{row.StatusDate}</span>
                )}
            </div>
        ),
    },
    {
        name: <H4>Connection Type</H4>,
        id: 'connection_type',
        selector: row => row.ConnectType,
        sortable: true,
        width: '140px',
    },
    {
        name: <H4>Serial No</H4>,
        id: 'serial_no',
        selector: row => row.Serial,
        sortable: true,
        wrap: true
    },
    {
        name: <H4>Stb Type</H4>,
        id: 'type',
        selector: row => row.StbType,
        sortable: true,
        width: '100px',
    },
    {
        name: <H4>STB No</H4>,
        id: 'stb_no',
        selector: row => row.StbNo,
        sortable: true,
        width: '100px',
    },
    {
        name: <H4>Install Date</H4>,
        id: 'activated_at',
        selector: row => row.Date,
        sortable: true,
        width: '130px',
        wrap: true
    },
    {
        name: <H4>Cas Provider</H4>,
        id: 'provider_name',
        selector: row => row.Cas,
        width: '130px',
        sortable: true,
        
    },
    {
        name: <H4>Location</H4>,
        id: 'adress',
        selector: row => row.address,
        width: '170px',
        sortable: true,
    },
];